def gen(rng, size):
    n = rng.randint(1, max(1, size))
    adj = [set() for _ in range(n)]
    # split nodes into two groups and add cross edges to bias toward bipartite
    side = [rng.randint(0, 1) for _ in range(n)]
    for u in range(n):
        for v in range(u + 1, n):
            if side[u] != side[v] and rng.random() < 0.3:
                adj[u].add(v)
                adj[v].add(u)
    # occasionally inject a same-side edge to create an odd structure
    if n >= 2 and rng.random() < 0.4:
        same = [(u, v) for u in range(n) for v in range(u + 1, n) if side[u] == side[v]]
        if same:
            u, v = rng.choice(same)
            adj[u].add(v)
            adj[v].add(u)
    return [[sorted(a) for a in adj]]

