class Solution:
    def isBipartite(self, graph):
        from collections import deque
        n = len(graph)
        color = [0] * n
        for s in range(n):
            if color[s] != 0:
                continue
            color[s] = 1
            q = deque([s])
            while q:
                u = q.popleft()
                for v in graph[u]:
                    if color[v] == 0:
                        color[v] = -color[u]
                        q.append(v)
                    elif color[v] == color[u]:
                        return False
        return True

