var isBipartite = function(graph) {
    const n = graph.length;
    const color = new Array(n).fill(0);
    for (let s = 0; s < n; s++) {
        if (color[s] !== 0) continue;
        color[s] = 1;
        const q = [s];
        let head = 0;
        while (head < q.length) {
            const u = q[head++];
            for (const v of graph[u]) {
                if (color[v] === 0) {
                    color[v] = -color[u];
                    q.push(v);
                } else if (color[v] === color[u]) {
                    return false;
                }
            }
        }
    }
    return true;
};
